class DateStore{current_timezone="";source_date=null;timezone_date=null;detect_timezone(t){return t??"Etc/UTC"}constructor(t="2020-06-13T00:05:11+08:00[Asia/Taipei]",e="Etc/UTC"){this.current_timezone=this.detect_timezone(e),this.source_date=Temporal.Instant.from(t??new Date)}get result(){return this.source_date.toZonedDateTimeISO(this.current_timezone).toLocaleString(navigator.language,{hour12:!1})}}export class IDateComponentElement extends HTMLElement{constructor(){super()}get title(){return this.hasAttribute("data-title")?this.getAttribute("data-title"):"Date: "}get date(){return this.hasAttribute("data-date")?this.getAttribute("data-date"):"Unknown date"}date_store=null;get classes(){return this.hasAttribute("data-classes")?this.getAttribute("data-classes"):"date"}connectedCallback(){this.date_store=new DateStore(this.date,this.hasAttribute("data-timezone"));this.attachShadow({mode:"open"}).appendChild(this.wrapper_element())}wrapper_element(){const t=document.createElement("small");return t.setAttribute("title",`Source date: ${this.date}`),t.classList.add("date-component"),t.textContent=this.title,t.appendChild(this.time_element(this.classes,this.date)),t}time_element(){const t=document.createElement("time");return t.setAttribute("class",this.classes),t.setAttribute("datetime",this.date),t.textContent=this.date_store.result,t}}